package org.apache.commons.csv;
import static org.apache.commons.csv.Constants.COMMENT;
import static org.apache.commons.csv.Constants.CR;
import static org.apache.commons.csv.Constants.LF;
import static org.apache.commons.csv.Constants.SP;
import java.io.Closeable;
import java.io.Flushable;
import java.sql.ResultSet;
import java.sql.SQLException;

import static org.mockito.Mockito.*;

import java.io.IOException;
import java.lang.reflect.Field;
import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import static org.junit.jupiter.api.Assertions.*;

class CSVPrinterTest {

    private CSVPrinter printer;
    private Appendable out;
    private CSVFormat format;

    @BeforeEach
    void setUp() {
        out = mock(Appendable.class);
        format = mock(CSVFormat.class);
        printer = new CSVPrinter(out, format);
    }

    private void invokePrint(Object object, CharSequence value, int offset, int len) throws Throwable {
        Method printMethod = CSVPrinter.class.getDeclaredMethod("print", Object.class, CharSequence.class, int.class, int.class);
        printMethod.setAccessible(true);
        try {
            printMethod.invoke(printer, object, value, offset, len);
        } catch (InvocationTargetException e) {
            throw e.getCause();
        }
    }

    @Test
    void testPrint_NewRecordTrue_Quoting() throws Throwable {
        // newRecord true initially, so no delimiter appended
        when(format.isQuoting()).thenReturn(true);
        when(format.isEscaping()).thenReturn(false);
        // Use a CharSequence value that covers offset and len
        CharSequence value = "hello world";
        // Spy on printer to verify printAndQuote call
        CSVPrinter spyPrinter = spy(printer);

        // Replace printer with spy for invocation
        Method printMethod = CSVPrinter.class.getDeclaredMethod("print", Object.class, CharSequence.class, int.class, int.class);
        printMethod.setAccessible(true);
        // Set newRecord true explicitly
        setFieldNewRecord(spyPrinter, true);

        // Mock private method printAndQuote via reflection proxying
        doNothing().when(spyPrinter).printAndQuoteProxy(any(), any(), anyInt(), anyInt());

        printMethod.invoke(spyPrinter, "obj", value, 0, 5);

        // Verify no delimiter appended because newRecord was true
        verify(out, never()).append(any(CharSequence.class));

        // Verify printAndQuoteProxy called
        verify(spyPrinter).printAndQuoteProxy("obj", value, 0, 5);

        // newRecord should be false after call
        assertFalse(getFieldNewRecord(spyPrinter));
    }

    @Test
    void testPrint_NewRecordFalse_Quoting() throws Throwable {
        when(format.isQuoting()).thenReturn(true);
        when(format.isEscaping()).thenReturn(false);
        CharSequence value = "hello world";

        CSVPrinter spyPrinter = spy(printer);
        setFieldNewRecord(spyPrinter, false);

        doNothing().when(spyPrinter).printAndQuoteProxy(any(), any(), anyInt(), anyInt());

        Method printMethod = CSVPrinter.class.getDeclaredMethod("print", Object.class, CharSequence.class, int.class, int.class);
        printMethod.setAccessible(true);
        printMethod.invoke(spyPrinter, "obj", value, 0, 5);

        // Verify delimiter appended once
        verify(out).append(format.getDelimiter());

        verify(spyPrinter).printAndQuoteProxy("obj", value, 0, 5);

        assertFalse(getFieldNewRecord(spyPrinter));
    }

    @Test
    void testPrint_NewRecordFalse_Escaping() throws Throwable {
        when(format.isQuoting()).thenReturn(false);
        when(format.isEscaping()).thenReturn(true);
        CharSequence value = "abcdef";

        CSVPrinter spyPrinter = spy(printer);
        setFieldNewRecord(spyPrinter, false);

        doNothing().when(spyPrinter).printAndEscapeProxy(any(), anyInt(), anyInt());

        Method printMethod = CSVPrinter.class.getDeclaredMethod("print", Object.class, CharSequence.class, int.class, int.class);
        printMethod.setAccessible(true);
        printMethod.invoke(spyPrinter, "obj", value, 1, 3);

        verify(out).append(format.getDelimiter());

        verify(spyPrinter).printAndEscapeProxy(value, 1, 3);

        assertFalse(getFieldNewRecord(spyPrinter));
    }

    @Test
    void testPrint_NewRecordFalse_NoQuotingNoEscaping() throws Throwable {
        when(format.isQuoting()).thenReturn(false);
        when(format.isEscaping()).thenReturn(false);
        CharSequence value = "abcdef";

        setFieldNewRecord(printer, false);

        Method printMethod = CSVPrinter.class.getDeclaredMethod("print", Object.class, CharSequence.class, int.class, int.class);
        printMethod.setAccessible(true);
        printMethod.invoke(printer, "obj", value, 2, 3);

        // Verify delimiter appended
        verify(out).append(format.getDelimiter());

        // Verify append called with correct subsequence
        // Since Appendable.append(CharSequence, int, int) is called with offset=2, offset+len=5
        verify(out).append(value, 2, 5);

        assertFalse(getFieldNewRecord(printer));
    }

    // Helper methods to access private boolean newRecord field
    private void setFieldNewRecord(CSVPrinter printerInstance, boolean value) throws Exception {
        Field field = CSVPrinter.class.getDeclaredField("newRecord");
        field.setAccessible(true);
        field.set(printerInstance, value);
    }

    private boolean getFieldNewRecord(CSVPrinter printerInstance) throws Exception {
        Field field = CSVPrinter.class.getDeclaredField("newRecord");
        field.setAccessible(true);
        return (boolean) field.get(printerInstance);
    }

    // Add proxy methods to call the private methods via reflection
    // This avoids direct calls to private methods in Mockito verify/doNothing

    // printAndQuote proxy
    @SuppressWarnings("unused")
    private void printAndQuoteProxy(Object object, CharSequence value, int offset, int len) throws Throwable {
        Method m = CSVPrinter.class.getDeclaredMethod("printAndQuote", Object.class, CharSequence.class, int.class, int.class);
        m.setAccessible(true);
        try {
            m.invoke(printer, object, value, offset, len);
        } catch (InvocationTargetException e) {
            throw e.getCause();
        }
    }

    // printAndEscape proxy
    @SuppressWarnings("unused")
    private void printAndEscapeProxy(CharSequence value, int offset, int len) throws Throwable {
        Method m = CSVPrinter.class.getDeclaredMethod("printAndEscape", CharSequence.class, int.class, int.class);
        m.setAccessible(true);
        try {
            m.invoke(printer, value, offset, len);
        } catch (InvocationTargetException e) {
            throw e.getCause();
        }
    }

    // To allow Mockito spying and mocking, we need to add these proxy methods to CSVPrinter via subclassing
    // So let's create a subclass that exposes these proxy methods

    // We'll do this by creating a spy subclass of CSVPrinter in @BeforeEach

    @BeforeEach
    void setUpSpy() {
        // Replace printer with a spy subclass that exposes proxy methods
        printer = new CSVPrinterWithProxies(out, format);
    }

    static class CSVPrinterWithProxies extends CSVPrinter {
        CSVPrinterWithProxies(Appendable out, CSVFormat format) {
            super(out, format);
        }

        void printAndQuoteProxy(Object object, CharSequence value, int offset, int len) throws Throwable {
            Method m = CSVPrinter.class.getDeclaredMethod("printAndQuote", Object.class, CharSequence.class, int.class, int.class);
            m.setAccessible(true);
            try {
                m.invoke(this, object, value, offset, len);
            } catch (InvocationTargetException e) {
                throw e.getCause();
            }
        }

        void printAndEscapeProxy(CharSequence value, int offset, int len) throws Throwable {
            Method m = CSVPrinter.class.getDeclaredMethod("printAndEscape", CharSequence.class, int.class, int.class);
            m.setAccessible(true);
            try {
                m.invoke(this, value, offset, len);
            } catch (InvocationTargetException e) {
                throw e.getCause();
            }
        }
    }
}
